+
+/// Quotes a string for safe inclusion in a shell command string.
+fn quote_str(s: &str) -> String {
+    if s.is_empty() {
+        return "''".to_string();
+    }
+    if !s.chars().any(|c| matches!(c, ' ' | '\t' | '\n' | '\\' | '\'' | '"' | '$' | '&' | '|' | ';' | '<' | '>' | '`' | '*' | '?' | '[' | ']' | '(' | ')' | '{' | '}' | '~' | '^' | '#')) {
+        return s.to_string();
+    }
+    let mut out = String::with_capacity(s.len() + 2);
+    out.push('\'');
+    for c in s.chars() {
+        if c == '\'' {
+            out.push_str("'\\''");
+        } else {
+            out.push(c);
+        }
+    }
+    out.push('\'');
+    out
+}
